from pathlib import Path
import shutil, os, fnmatch
src = Path('/opt/hermes')
dst = Path('/opt/data/hermesbackup-workdir')
exclude_dirs = {'.venv','node_modules','.playwright','.pytest_cache','.mypy_cache','.ruff_cache','__pycache__','build','dist','htmlcov','.vscode','.idea'}
exclude_names = {'.DS_Store','Thumbs.db','.coverage'}
exclude_globs = ['*.pyc','*.pyo','*.pyd','*.egg-info']

def excluded(path: Path):
    parts = path.parts
    if any(p in exclude_dirs for p in parts):
        return True
    name = path.name
    if name in exclude_names:
        return True
    return any(fnmatch.fnmatch(name, g) for g in exclude_globs)

# clean dst except itself
for item in dst.iterdir():
    if item.is_dir() and not item.is_symlink():
        shutil.rmtree(item)
    else:
        item.unlink()

count = 0
for root, dirs, files in os.walk(src):
    rootp = Path(root)
    rel = rootp.relative_to(src)
    # prune dirs
    dirs[:] = [d for d in dirs if not excluded(rootp / d)]
    target_dir = dst / rel
    target_dir.mkdir(parents=True, exist_ok=True)
    for f in files:
        sp = rootp / f
        if excluded(sp):
            continue
        dp = target_dir / f
        shutil.copy2(sp, dp)
        count += 1
print(count)
